(function(w){"use strict";const ID="compound";function compute(x){const p=Number(x.principal),rate=Number(x.rate),years=Number(x.years),n=Number(x.compounds);if(![p,rate,years,n].every(Number.isFinite)||p<0||rate<0||years<0||n<=0)return{error:"원금·금리·기간·복리주기를 올바르게 입력해 주세요."};const fv=p*Math.pow(1+rate/100/n,n*years);return{future:fv,interest:fv-p}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>원금 (원)</label><input class="hm-calc-input" inputmode="numeric"></div><div class="hm-calc-field"><label>연 이자율 (%)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>기간 (년)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>연간 복리 횟수</label><select class="hm-calc-select"><option value="1">연 1회</option><option value="4">분기 4회</option><option value="12" selected>월 12회</option><option value="365">일 365회</option></select></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">복리 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const ins=root.querySelectorAll("input"),n=root.querySelector("select"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({principal:api.parseNumber(ins[0].value),rate:api.parseNumber(ins[1].value),years:api.parseNumber(ins[2].value),compounds:api.parseNumber(n.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("예상 미래가치",api.formatWon(r.future),`<dl><dt>예상 이자</dt><dd>${api.formatWon(r.interest)}</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
